<?php require_once __DIR__ . '/../includes/admin.php';admin_required();$message='';if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf($_POST['csrf']??null);$current=$_POST['current_password']??'';$new=$_POST['new_password']??'';$s=db()->prepare('SELECT password FROM admin WHERE id=?');$s->execute([$_SESSION['admin_id']]);if(!password_verify($current,$s->fetchColumn()?:''))$message='Current password is incorrect.';elseif(strlen($new)<10)$message='Use a password with at least 10 characters.';else{db()->prepare('UPDATE admin SET password=? WHERE id=?')->execute([password_hash($new,PASSWORD_DEFAULT),$_SESSION['admin_id']]);$message='Password updated successfully.';}}admin_head('Settings'); ?><h1>Settings</h1><form class="card" method="post"><h2>Change password</h2><p class="<?=str_contains($message,'success')?'success':'error'?>"><?=e($message)?></p><input type="hidden" name="csrf" value="<?=csrf_token()?>"><input type="password" name="current_password" placeholder="Current password" required><input type="password" name="new_password" placeholder="New password (10+ characters)" minlength="10" required><button>Update password</button></form><?php admin_foot(); ?>
